#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
#define MAXK 300005
int T, N, K;
int graph[MAXN * 2][MAXN * 2];
int visited[MAXN * 2];
void dfs(int node) {
    visited[node] = 1;
    for (int i = 0; i < N * 2; i++) {
        if (graph[node][i] && !visited[i]) {
            dfs(i);
        }
    }
}
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N * 2; i++) {
            for (int j = 0; j < N * 2; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < K; i++) {
            int A, B;
            scanf("%d %d", &A, &B);
            if (A > 0) {
                graph[N + A][A - 1] = 1;
            } else {
                graph[-A + N - 1][N - A] = 1;
            }
            if (B > 0) {
                graph[N + B][B - 1] = 1;
            } else {
                graph[-B + N - 1][N - B] = 1;
            }
        }
        int conflict = 0;
        for (int i = 0; i < N * 2; i++) {
            if (!visited[i]) {
                dfs(i);
            }
        }
        for (int i = 0; i < N; i++) {
            if (visited[i] && visited[i + N]) {
                conflict = 1;
                break;
            }
        }
        if (conflict) {
            printf("CONFLICT\n");
        } else {
            int unique = 1;
            for (int i = 0; i < N; i++) {
                if (!visited[i] && !visited[i + N]) {
                    unique = 0;
                    break;
                }
            }
            if (unique) {
                printf("UNIQUE\n");
            } else {
                printf("MULTIPLE\n");
            }
        }
        for (int i = 0; i < N * 2; i++) {
            visited[i] = 0;
        }
    }
    return 0;
}

