public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[][] graph = new int[N * 2][N * 2];
            int[] visited = new int[N * 2];
            for (int i = 0; i < K; i++) {
                int A = sc.nextInt();
                int B = sc.nextInt();
                if (A > 0) {
                    graph[N + A][A - 1] = 1;
                } else {
                    graph[-A + N - 1][N - A] = 1;
                }
                if (B > 0) {
                    graph[N + B][B - 1] = 1;
                } else {
                    graph[-B + N - 1][N - B] = 1;
                }
            }
            int conflict = 0;
            for (int i = 0; i < N * 2; i++) {
                if (visited[i] == 0) {
                    dfs(graph, visited, i);
                }
            }
            for (int i = 0; i < N; i++) {
                if (visited[i] == 1 && visited[i + N] == 1) {
                    conflict = 1;
                    break;
                }
            }
            if (conflict == 1) {
                System.out.println("CONFLICT");
            } else {
                int unique = 1;
                for (int i = 0; i < N; i++) {
                    if (visited[i] == 0 && visited[i + N] == 0) {
                        unique = 0;
                        break;
                    }
                }
                if (unique == 1) {
                    System.out.println("UNIQUE");
                } else {
                    System.out.println("MULTIPLE");
                }
            }
            for (int i = 0; i < N * 2; i++) {
                visited[i] = 0;
            }
        }
    }
    public static void dfs(int[][] graph, int[] visited, int node) {
        visited[node] = 1;
        for (int i = 0; i < graph.length; i++) {
            if (graph[node][i] == 1 && visited[i] == 0) {
                dfs(graph, visited, i);
            }
        }
    }
}

